152 #ifndef NDEBUG
153   for (auto &[V, Index] : Value2Index) {
154     std::string OperandName;
155     if (V->getName().empty())
156       OperandName = V->getNameOrAsOperand();
157     else
158       OperandName = std::string("%") + V->getName().str();
