581 ConstraintInfo::getConstraint(CmpInst::Predicate Pred, Value *Op0, Value *Op1,
582                               SmallVectorImpl<Value *> &NewVariables) const {
583   assert(NewVariables.empty() && "NewVariables must be empty when passed in");
